fn init(buffer: &mut BBuf, config: &BatchConfig) {
    let writer = buffer.writer();
    if config.is_streamed {
        let _ = writer.write_exact(&BatchSize::MIN.to_be_bytes());
    }
    if let Some(h) = config.header() {
        let _ = writer.write_u8(h.as_u8());
    }
}

